localparam CENTER = TAPS / 2;

// Pre-add symmetric pairs — skip the center tap
always_comb begin
  for (int i = 0; i < CENTER; i++)
    pre_add[i] = data_reg[i] + data_reg[TAPS-1-i];
end

// Multiply
always_comb begin
  for (int i = 0; i < CENTER; i++)
    mult[i] = pre_add[i] * coeff[i];
  // Center tap multiplied directly (odd TAPS only)
  mult[CENTER] = data_reg[CENTER] * coeff[CENTER];
end
